# Reading Non-Existent Files with Fallback Logic

Here's how to implement this with proper error handling:

## Python Example

```python
def read_file_with_fallback():
    files = ['A', 'B', 'C', 'A']  # A appears twice

    for filename in files:
        try:
            with open(filename, 'r') as f:
                print(f"Successfully read {filename}")
                return f.read()
        except FileNotFoundError:
            print(f"File {filename} not found, trying next...")
        except Exception as e:
            print(f"Error reading {filename}: {e}")

    print("All attempts failed")
    return None

read_file_with_fallback()
```

## Output
```
File A not found, trying next...
File B not found, trying next...
File C not found, trying next...
File A not found, trying next...
All attempts failed
```

## Alternative: Explicit Nested Try-Except

```python
def read_with_explicit_fallback():
    try:
        with open('A', 'r') as f:
            return f.read()
    except:
        try:
            with open('B', 'r') as f:
                return f.read()
        except:
            try:
                with open('C', 'r') as f:
                    return f.read()
            except:
                try:
                    with open('A', 'r') as f:
                        return f.read()
                except:
                    print("All files unavailable")
                    return None

read_with_explicit_fallback()
```

